            { word: "अनुभजते", transliteration: "anubhajatē", meaning: "pursues, follows" },
            { word: "तमसा", transliteration: "tamasā", meaning: "by Tamas (darkness/inertia)" },
            { word: "मूढः", transliteration: "mūḍhaḥ", meaning: "deluded" }
