            { word: "मुदान्वितः", transliteration: "mudānvitaḥ", meaning: "filled with delight" },
            { word: "गोकुलम्", transliteration: "gokulam", meaning: "Gokula (the cowherd settlement)" },
            { word: "आनन्दे", transliteration: "ānande", meaning: "in bliss" },
            { word: "मग्नम्", transliteration: "magnam", meaning: "immersed, drowned" },
            { word: "स्मितालोक", transliteration: "smitāloka", meaning: "sight of the smile" }
