            { word: "अञ्चिताङ्गं", transliteration: "añcitāṅgaṃ", meaning: "with decorated/adorned body" },
            { word: "मणिनिचयमयं", transliteration: "maṇinicayamayaṃ", meaning: "made of clusters of gems" },
            { word: "कुण्डलं", transliteration: "kuṇḍalaṃ", meaning: "ear-ring" },
            { word: "कर्णपाशे", transliteration: "karṇapāśe", meaning: "at the ear-lobes" },
            { word: "काञ्चीनूपुरकान्तं", transliteration: "kāñcīnūpurakāntaṃ", meaning: "beautiful with girdle and anklets" },
            { word: "कटकवलयिनं", transliteration: "kaṭakavalayinaṃ", meaning: "wearing bracelets and bangles" },
            { word: "दिव्यकेयूरभूषं", transliteration: "divyakeyūrabhūṣaṃ", meaning: "adorned with divine armlets" },
            { word: "नानारत्नोज्ज्वलाङ्गं", transliteration: "nānaratnojjvalāṅgaṃ", meaning: "body blazing with various gems" },
            { word: "भगवतः", transliteration: "bhagavataḥ", meaning: "of the Lord" },
            { word: "प्रकाशम्", transliteration: "prakāśam", meaning: "radiance, luminous manifestation" }
